// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";

contract Voting is Ownable {
    struct Candidate {
        uint256 id;
        string name;
        uint256 voteCount;
    }

    uint256 private candidateCount;

    mapping(uint256 => Candidate) private candidates;
    mapping(address => bool) public hasVoted;

    event CandidateAdded(uint256 indexed candidateId, string name);
    event VoteCast(address indexed voter, uint256 indexed candidateId);

    constructor(address initialOwner) Ownable(initialOwner) {}

    function addCandidate(string calldata name) external onlyOwner returns (uint256) {
        require(bytes(name).length > 0, "Candidate name required");

        candidateCount += 1;
        candidates[candidateCount] = Candidate({
            id: candidateCount,
            name: name,
            voteCount: 0
        });

        emit CandidateAdded(candidateCount, name);
        return candidateCount;
    }

    function vote(uint256 candidateId) external {
        require(candidateId > 0 && candidateId <= candidateCount, "Invalid candidate");
        require(!hasVoted[msg.sender], "Already voted");

        hasVoted[msg.sender] = true;
        candidates[candidateId].voteCount += 1;

        emit VoteCast(msg.sender, candidateId);
    }

    function getCandidate(uint256 candidateId)
        external
        view
        returns (uint256 id, string memory name, uint256 voteCount)
    {
        require(candidateId > 0 && candidateId <= candidateCount, "Invalid candidate");
        Candidate memory candidate = candidates[candidateId];
        return (candidate.id, candidate.name, candidate.voteCount);
    }

    function getResults()
        external
        view
        returns (
            uint256[] memory ids,
            string[] memory names,
            uint256[] memory voteCounts
        )
    {
        ids = new uint256[](candidateCount);
        names = new string[](candidateCount);
        voteCounts = new uint256[](candidateCount);

        for (uint256 i = 1; i <= candidateCount; i++) {
            Candidate memory candidate = candidates[i];
            uint256 index = i - 1;
            ids[index] = candidate.id;
            names[index] = candidate.name;
            voteCounts[index] = candidate.voteCount;
        }
    }

    function totalCandidates() external view returns (uint256) {
        return candidateCount;
    }
}

